request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?taskCount ?eventCount ?gatewayCount ?flowCount ?participantCount WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo bbo:name ?choreoName .
  ?choreo tai:belongsTo ?model .
  ?model tai:normalizedId "sid_86d8a78f_54c4_423d_92e1_edf43db849dc" .

  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?event) AS ?eventCount) WHERE {
      ?event a bboExt:StartEvent .
      ?event tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?gw) AS ?gatewayCount) WHERE {
      ?gw a bboExt:ExclusiveGateway .
      ?gw tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?flow) AS ?flowCount) WHERE {
      ?flow a bbo:SequenceFlow .
      ?flow tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?part) AS ?participantCount) WHERE {
      ?part a bboExt:Participant .
      ?part tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
}
LIMIT 25
